function pickValid(x) {
  if (!x) return null;
  const base = Number(x.pt_base);
  const bear = Number(x.pt_bear);
  const bull = Number(x.pt_bull);
  const conf = Number(x.confidence);
  if (!x.stock) return null;
  if (!isFinite(base) || base <= 0) return null;
  if (!isFinite(bear) || bear <= 0) return null;
  if (!isFinite(bull) || bull <= 0) return null;
  if (!isFinite(conf) || conf <= 0) return null;
  return x;
}

const byStock = new Map();

for (const it of items) {
  const j = it.json || {};

  // Candidate extraction (supports either chatgpt_result, gemini_result, or already flattened)
  const candidates = [];

  if (j.chatgpt_result && typeof j.chatgpt_result === "object") {
    candidates.push({ ...j.chatgpt_result, model: "CHATGPT" });
  }

  if (j.gemini_result && typeof j.gemini_result === "object") {
    candidates.push({ ...j.gemini_result, model: "GEMINI" });
  }

  // fallback if something arrives already flattened
  if (candidates.length === 0 && j.stock && (j.pt_base || j.pt_bear || j.pt_bull)) {
    candidates.push({ ...j, model: j.model || "UNKNOWN" });
  }

  for (const cand of candidates) {
    const stock = cand.stock || j.stock || "";
    const normalized = {
      stock,
      date: cand.date || null,
      pt_bear: Number(cand.pt_bear ?? NaN),
      pt_base: Number(cand.pt_base ?? NaN),
      pt_bull: Number(cand.pt_bull ?? NaN),
      f_score: (cand.f_score ?? null),
      confidence: Number(cand.confidence ?? NaN),
      rationale: cand.rationale || "",
      model: cand.model || "UNKNOWN"
    };

    const valid = pickValid(normalized);
    if (!valid) continue;

    if (!byStock.has(stock)) byStock.set(stock, []);
    byStock.get(stock).push(valid);
  }
}

const today = new Date().toISOString().slice(0, 10);

const out = [];
for (const [stock, arr] of byStock.entries()) {
  // Optional: dedupe per model (keep highest confidence per model)
  const bestByModel = new Map();
  for (const r of arr) {
    const key = r.model;
    const prev = bestByModel.get(key);
    if (!prev || (r.confidence ?? 0) > (prev.confidence ?? 0)) {
      bestByModel.set(key, r);
    }
  }

  // Emit one row per model
  for (const r of bestByModel.values()) {
    const date = r.date || today;

    out.push({
      json: {
        stock,
        date,
        pt_bear: Number(r.pt_bear.toFixed(2)),
        pt_base: Number(r.pt_base.toFixed(2)),
        pt_bull: Number(r.pt_bull.toFixed(2)),
        f_score: r.f_score,
        confidence: Math.max(20, Math.min(90, Number(r.confidence.toFixed(0)))),
        rationale: r.rationale || "No rationale provided",
        model: r.model,
        // Use this as your Google Sheets upsert key to avoid overwriting
        row_key: `${stock}_${date}_${r.model}`,
        skip_row: false
      }
    });
  }
}

if (out.length === 0) {
  return [{
    json: {
      stock: "",
      date: today,
      pt_bear: 0,
      pt_base: 0,
      pt_bull: 0,
      confidence: 0,
      rationale: "No valid analyst data",
      model: "ERROR",
      row_key: `ERROR_${today}`,
      skip_row: true
    }
  }];
}

return out;

const FRESH_DAYS = 7;
const now = Date.now();

const row = items?.[0]?.json ?? null;

function parseDateMs(v) {
  if (!v) return null;
  const t = Date.parse(v);
  return Number.isFinite(t) ? t : null;
}

const cacheHit = !!(row && row.stock);

let shouldFetch = false;
let reason = '';
let ageDays = null;

if (!cacheHit) {
  shouldFetch = true;
  reason = 'cache_miss';
} else {
  const updatedMs = parseDateMs(row.last_updated);

  if (!updatedMs) {
    shouldFetch = true;
    reason = 'missing_last_updated';
  } else {
    ageDays = (now - updatedMs) / 86400000;
    shouldFetch = ageDays >= FRESH_DAYS;
    reason = shouldFetch ? `stale_${ageDays.toFixed(2)}d` : `fresh_${ageDays.toFixed(2)}d`;
  }
}

return [{
  json: {
    stock: row?.stock || $json.stock,
    cacheHit,                 // ✅ this is the one you’ll use for update vs append
    shouldFetch,              // ✅ this is only for API call decision
    reason,
    ageDays,
    cacheRow: row || null,
    nowISO: new Date(now).toISOString(),
  }
}];

const inJson = $json || {};
const stock =
  inJson.stock ||
  inJson.Symbol ||
  inJson.symbol ||
  (items && items[0] && items[0].json && items[0].json.stock) ||
  "UNKNOWN";

return [
  {
    json: {
      stock: stock,
      income_data: inJson
    }
  }
];

const inJson = $json || {};
const stock =
  inJson.stock ||
  inJson.Symbol ||
  inJson.symbol ||
  (items && items[0] && items[0].json && items[0].json.stock) ||
  "UNKNOWN";

return [
  {
    json: {
      stock: stock,
      cashflow_data: inJson
    }
  }
];

// Helper function to safely get numbers
function num(value) {
  if (value === null || value === undefined || value === 'None' || value === '') return null;
  const n = Number(String(value).replace(/[,$%]/g, ''));
  return isFinite(n) ? n : null;
}

// Get data from the API responses
const overview = $json.overview_data || {};
const income = $json.income_data || {};
const balance = $json.balance_data || {};
const cashflow = $json.cashflow_data || {}; // optional (only if you add CASH_FLOW endpoint)
const current_price = num($json.current_price); // null if missing


// Extract reports
const quarterlyReports = income.quarterlyReports || [];
const balanceQuarterly = balance.quarterlyReports || [];

// Revenue last 4 quarters
const revenue_last_4q = quarterlyReports.slice(0, 4).map(q => num(q.totalRevenue));

// Net income last 4 quarters
const net_income_last_4q = quarterlyReports.slice(0, 4).map(q => num(q.netIncome));

// Gross margin last 4 quarters (calculate from revenue and cost)
const gross_margin_last_4q = quarterlyReports.slice(0, 4).map(q => {
  const rev = num(q.totalRevenue);
  const cogs = num(q.costOfRevenue);
  if (rev !== null && cogs !== null && rev > 0) {
    return Number((((rev - cogs) / rev) * 100).toFixed(2));
  }
  return null;
});

// Total debt last 4 quarters
const total_debt_last_4q = balanceQuarterly.slice(0, 4).map(q => {
  const shortTerm = num(q.shortTermDebt) || 0;
  const longTerm = num(q.longTermDebt) || 0;
  const total = shortTerm + longTerm;
  return total > 0 ? total : null;
});

// Cash last 4 quarters
const cash_last_4q = balanceQuarterly
  .slice(0, 4)
  .map(q => num(q.cashAndCashEquivalentsAtCarryingValue));


const debt_latest =
  total_debt_last_4q && total_debt_last_4q.length
    ? total_debt_last_4q[0]
    : null;

const cash_latest =
  cash_last_4q && cash_last_4q.length
    ? cash_last_4q[0]
    : null;

let net_debt_latest = null;
let net_cash_flag = null;

if (debt_latest !== null && cash_latest !== null) {
  net_debt_latest = debt_latest - cash_latest;
  net_cash_flag = net_debt_latest < 0;
}
// Revenue growth YoY (quarter 0 vs quarter 3)
let revenue_growth_yoy = null;
if (revenue_last_4q.length >= 4 && revenue_last_4q[0] !== null && revenue_last_4q[3] !== null && revenue_last_4q[3] !== 0) {
  revenue_growth_yoy = Number((((revenue_last_4q[0] - revenue_last_4q[3]) / revenue_last_4q[3]) * 100).toFixed(2));
}

// ---- FIX 1: total_debt_ttm should come from BALANCE sheet (latest quarter) ----
const latestBQ = balanceQuarterly && balanceQuarterly.length ? balanceQuarterly[0] : null;

let total_debt_ttm = null;
if (latestBQ) {
  const shortTerm = num(latestBQ.shortTermDebt) || 0;
  const longTerm = num(latestBQ.longTermDebt) || 0;
  const total = shortTerm + longTerm;
  total_debt_ttm = total > 0 ? total : null;
}

// ---- FIX 2: operating margin can be decimal (0.12) OR percent (12.0) ----
let operating_margin_ttm = num(overview.OperatingMarginTTM);
if (operating_margin_ttm !== null) {
  // if it's a fraction, convert to percent
  if (Math.abs(operating_margin_ttm) <= 1.5) {
    operating_margin_ttm = operating_margin_ttm * 100;
  }
  operating_margin_ttm = Number(operating_margin_ttm.toFixed(2));
}

// ---- FIX 3: fcf_ttm (real FCF) only if you have CASH_FLOW endpoint ----
// Alpha Vantage doesn't reliably give FCF in OVERVIEW.
// Compute: FCF = OperatingCashflow + CapitalExpenditures (capex is usually negative)
let fcf_ttm = null;

const cfAnnual = cashflow.annualReports || [];
const cfQuarterly = cashflow.quarterlyReports || [];

let ocf = null;
let capex = null;

if (cfAnnual.length) {
  ocf = num(cfAnnual[0].operatingCashflow);
  capex = num(cfAnnual[0].capitalExpenditures);
}

if ((ocf === null || capex === null) && cfQuarterly.length >= 4) {
  const last4 = cfQuarterly.slice(0,4);
  const ocfList = last4.map(r=>num(r.operatingCashflow));
  const capexList = last4.map(r=>num(r.capitalExpenditures));

  if (ocfList.every(v=>v!==null) && capexList.every(v=>v!==null)) {
    ocf = ocfList.reduce((a,b)=>a+b,0);
    capex = capexList.reduce((a,b)=>a+b,0);
  }
}

if (ocf!==null && capex!==null) fcf_ttm = ocf + capex;

// Gross margin TTM (from overview fields)
let gross_margin_ttm = null;
const grossProfitTTM = num(overview.GrossProfitTTM);
const revenueTTM = num(overview.RevenueTTM);
if (grossProfitTTM !== null && revenueTTM !== null && revenueTTM !== 0) {
  gross_margin_ttm = Number(((grossProfitTTM / revenueTTM) * 100).toFixed(2));
}
const net_income_ttm = net_income_last_4q.reduce((a,b)=>a+(b||0),0);
// --------------------
// Piotroski F-Score (0-9) using annualReports[0] vs annualReports[1]
// If a component can't be computed, it scores 0 (conservative).
// --------------------
function safeDiv(a, b) {
  if (a === null || b === null || b === 0) return null;
  return a / b;
}

const incA = income.annualReports || [];
const balA = balance.annualReports || [];
const cfA  = cashflow.annualReports || [];

const y0_inc = incA.length >= 1 ? incA[0] : null;
const y1_inc = incA.length >= 2 ? incA[1] : null;

const y0_bal = balA.length >= 1 ? balA[0] : null;
const y1_bal = balA.length >= 2 ? balA[1] : null;

const y0_cf  = cfA.length >= 1 ? cfA[0] : null;
const y1_cf  = cfA.length >= 2 ? cfA[1] : null;

let f_score = 0;
const f_detail = {}; // optional debug

// Helper getters
const NI0 = y0_inc ? num(y0_inc.netIncome) : null;
const NI1 = y1_inc ? num(y1_inc.netIncome) : null;

const TA0 = y0_bal ? num(y0_bal.totalAssets) : null;
const TA1 = y1_bal ? num(y1_bal.totalAssets) : null;

const CFO0 = y0_cf ? num(y0_cf.operatingCashflow) : null;
const CFO1 = y1_cf ? num(y1_cf.operatingCashflow) : null;

const LTD0 = y0_bal ? num(y0_bal.longTermDebt) : null;
const LTD1 = y1_bal ? num(y1_bal.longTermDebt) : null;

const CA0 = y0_bal ? num(y0_bal.totalCurrentAssets) : null;
const CA1 = y1_bal ? num(y1_bal.totalCurrentAssets) : null;

const CL0 = y0_bal ? num(y0_bal.totalCurrentLiabilities) : null;
const CL1 = y1_bal ? num(y1_bal.totalCurrentLiabilities) : null;

const REV0 = y0_inc ? num(y0_inc.totalRevenue) : null;
const REV1 = y1_inc ? num(y1_inc.totalRevenue) : null;

const GP0 = y0_inc ? num(y0_inc.grossProfit) : null;
const GP1 = y1_inc ? num(y1_inc.grossProfit) : null;

// Shares outstanding (dilution check)
// Prefer annual balance sheet shares if available; otherwise we can't score it reliably.
const SH0 = y0_bal ? num(y0_bal.commonStockSharesOutstanding) : null;
const SH1 = y1_bal ? num(y1_bal.commonStockSharesOutstanding) : null;

// ---- PROFITABILITY (4) ----
// F1: Positive net income
if (NI0 !== null && NI0 > 0) { f_score++; f_detail.F1_NI_pos = 1; } else f_detail.F1_NI_pos = 0;

// F2: Positive CFO
if (CFO0 !== null && CFO0 > 0) { f_score++; f_detail.F2_CFO_pos = 1; } else f_detail.F2_CFO_pos = 0;

// F3: ROA improving (NI/TA)
const ROA0 = safeDiv(NI0, TA0);
const ROA1 = safeDiv(NI1, TA1);
if (ROA0 !== null && ROA1 !== null && ROA0 > ROA1) { f_score++; f_detail.F3_ROA_up = 1; } else f_detail.F3_ROA_up = 0;

// F4: Accruals: CFO > NI
if (CFO0 !== null && NI0 !== null && CFO0 > NI0) { f_score++; f_detail.F4_CFO_gt_NI = 1; } else f_detail.F4_CFO_gt_NI = 0;

// ---- LEVERAGE / LIQUIDITY (3) ----
// F5: Lower long-term debt
if (LTD0 !== null && LTD1 !== null && LTD0 < LTD1) { f_score++; f_detail.F5_LTD_down = 1; } else f_detail.F5_LTD_down = 0;

// F6: Higher current ratio (CA/CL)
const CR0 = safeDiv(CA0, CL0);
const CR1 = safeDiv(CA1, CL1);
if (CR0 !== null && CR1 !== null && CR0 > CR1) { f_score++; f_detail.F6_CR_up = 1; } else f_detail.F6_CR_up = 0;

// F7: No dilution (shares not increased)
if (SH0 !== null && SH1 !== null && SH0 <= SH1) { f_score++; f_detail.F7_no_dilution = 1; } else f_detail.F7_no_dilution = 0;

// ---- OPERATING EFFICIENCY (2) ----
// F8: Gross margin improved (GP/REV)
const GM0 = (GP0 !== null && REV0) ? safeDiv(GP0, REV0) : null;
const GM1 = (GP1 !== null && REV1) ? safeDiv(GP1, REV1) : null;
if (GM0 !== null && GM1 !== null && GM0 > GM1) { f_score++; f_detail.F8_GM_up = 1; } else f_detail.F8_GM_up = 0;

// F9: Asset turnover improved (REV/TA)
const AT0 = safeDiv(REV0, TA0);
const AT1 = safeDiv(REV1, TA1);
if (AT0 !== null && AT1 !== null && AT0 > AT1) { f_score++; f_detail.F9_AT_up = 1; } else f_detail.F9_AT_up = 0;

// If we lack the minimum annual data, f_score is still computed conservatively (likely low).
// You can also flag completeness:
const f_score_data_ok = !!(y0_inc && y1_inc && y0_bal && y1_bal && y0_cf && y1_cf);
return {
  json: {
    stock: $json.stock || overview.Symbol || overview.symbol || "UNKNOWN",
    eps_current: num(overview.EPS),
    bvps_current: num(overview.BookValue),
    shares_outstanding: num(overview.SharesOutstanding),
    revenue_ttm: revenueTTM,

    // fixed
    total_debt_ttm: total_debt_ttm,

    gross_margin_ttm: gross_margin_ttm,
    operating_margin_ttm: operating_margin_ttm,

    // fixed: real FCF only if CASH_FLOW is available; otherwise stays null
    fcf_ttm: fcf_ttm,
    net_income_ttm,
    revenue_last_4q: revenue_last_4q.every(v => v !== null) ? revenue_last_4q : null,
    net_income_last_4q: net_income_last_4q.every(v => v !== null) ? net_income_last_4q : null,
    gross_margin_last_4q: gross_margin_last_4q.some(v => v !== null) ? gross_margin_last_4q : null,
    total_debt_last_4q: total_debt_last_4q.some(v => v !== null) ? total_debt_last_4q : null,
    cash_last_4q: cash_last_4q.some(v => v !== null) ? cash_last_4q : null,
    revenue_growth_yoy: revenue_growth_yoy,
    current_price,
net_debt_latest,
cash_latest,
debt_latest,
net_cash_flag,
    f_score,
f_score_data_ok,
    cache: {
      status: "refreshed",
      source: "api",
      last_updated: $json.last_updated || $json.nowISO || null
    }
  }
};

const inJson = $json || {};
const q = inJson["Global Quote"] || {};   // ← this was missing

const stock =
  q["01. symbol"] ||
  inJson.stock ||
  inJson.Symbol ||
  inJson.symbol ||
  "UNKNOWN";

return [
  {
    json: {
      stock: stock,
      current_price: Number(q["05. price"]) || null
    }
  }
];

// Carry stock forward
const stock =
  $json.stock ??
  $json.ticker ??
  ($node["loop_over_tickers"]?.json?.stock ?? "");

// Find XML - CHECK sa_xml FIRST (your custom output field)
let saXml =
  (typeof $json.sa_xml === "string" && $json.sa_xml.trim()) ? $json.sa_xml.trim() :
  (typeof $json.body === "string" && $json.body.trim()) ? $json.body.trim() :
  (typeof $json.data === "string" && $json.data.trim()) ? $json.data.trim() :
  (typeof $json.responseBody === "string" && $json.responseBody.trim()) ? $json.responseBody.trim() :
  (typeof $json.text === "string" && $json.text.trim()) ? $json.text.trim() :
  null;

// If your HTTP node returns binary, try decode first binary field
if (!saXml && $binary) {
  const key = Object.keys($binary)[0];
  const b64 = key && $binary[key] && $binary[key].data ? $binary[key].data : null;
  if (b64) {
    saXml = Buffer.from(b64, "base64").toString("utf8").trim();
    if (!saXml) saXml = null;
  }
}

// ALWAYS return json as an OBJECT
return {
  json: {
    stock,
    sa_xml: saXml,
    sa_ok: !!saXml
  }
};

return {
  json: {
    stock: $json.stock ?? "",
    seekingAlphaWindowHours: 80,
    seekingAlphaCount: 0,
    seekingAlphaNews: [],
    seekingAlphaNewsText: "",
    seekingAlphaError: $json.sa_error ?? "No XML to parse"
  }
};

// ---- CONFIG ----
const windowHours = 80;                 // recent window
const fallbackCount = 3;               // if no recent news, return latest N anyway
const now = Date.now();
const cutoff = now - windowHours * 3600 * 1000;

// ---- GET STOCK FROM INPUT ----
const stock =
  $input.first()?.json?.stock ??
  $json.stock ??
  "";

// ---- INPUT PATH ----
const items =
  $json?.rss?.channel?.item ??
  $json?.channel?.item ??
  $json?.item ??
  [];

const arr = Array.isArray(items) ? items : [items];

// ---- HELPERS ----
function cleanHtml(s) {
  if (!s) return "";
  return String(s)
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<\/?[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function toMillis(dateStr) {
  const t = Date.parse(dateStr);
  return Number.isFinite(t) ? t : NaN;
}

function getLink(i) {
  const l = i.link;
  if (!l) return "";
  if (typeof l === "string") return l;
  if (Array.isArray(l)) return getLink({ link: l[0] });
  return l["#text"] || l.href || l?.$?.href || "";
}

// ---- PARSE ALL ITEMS (no time filter yet) ----
const parsedAll = arr
  .map(i => {
    const publishedAt = i.pubDate || i.published || i.date || "";
    const t = toMillis(publishedAt);
    return {
      source: "SeekingAlpha_RSS",
      title: cleanHtml(i.title),
      link: getLink(i),
      publishedAt,
      publishedAtMs: t,
      snippet: cleanHtml(i.description || i.summary || i["content:encoded"])
    };
  })
  .filter(n => n.title && n.link && Number.isFinite(n.publishedAtMs))
  .sort((a, b) => b.publishedAtMs - a.publishedAtMs);

// ---- DEDUPE (keep newest first) ----
const seen = new Set();
const dedupedAll = [];
for (const n of parsedAll) {
  if (seen.has(n.link)) continue;
  seen.add(n.link);
  dedupedAll.push(n);
}

// ---- RECENT WINDOW ----
const recent = dedupedAll.filter(n => n.publishedAtMs >= cutoff);

// ---- FINAL SELECTION ----
// If no recent items, fallback to latest N overall
const selected = (recent.length > 0) ? recent : dedupedAll.slice(0, fallbackCount);
const hasRecent = recent.length > 0;

// ---- CREATE COMPACT TEXT ----
const seekingAlphaNewsText = selected.map(n => {
  const shortSnippet = n.snippet.length > 240 ? n.snippet.slice(0, 240) + "…" : n.snippet;
  return `- ${n.publishedAt} | ${n.title}\n  ${n.link}\n  Snippet: ${shortSnippet}`;
}).join("\n\n");

return [
  {
    json: {
      stock,
      seekingAlphaWindowHours: windowHours,

      // signals for the AI prompt later
      seekingAlphaHasRecent: hasRecent,
      seekingAlphaRecentCount: recent.length,

      // what you actually pass forward
      seekingAlphaCount: selected.length,
      seekingAlphaNews: selected.map(({ publishedAtMs, ...rest }) => rest),
      seekingAlphaNewsText,

      // optional: last coverage date (useful for prompt)
      seekingAlphaLatestDate: dedupedAll[0]?.publishedAt ?? null
    }
  }
];

let parsed = $json;

// Extract from ChatGPT nested structure
const t = $json?.output?.[0]?.content?.[0]?.text;

if (t) {
  if (typeof t === "string") {
    // sometimes text is a JSON string
    try {
      parsed = JSON.parse(t);
    } catch (e) {
      // keep original wrapper if parse fails
      parsed = $json;
    }
  } else if (typeof t === "object") {
    // sometimes text is already a JSON object (your case)
    parsed = t;
  }
}

const stock =
  parsed?.stock ||
  $json?.stock ||
  $json?.ticker ||
  $json?.symbol ||
  "UNKNOWN";

return {
  json: {
    chatgpt_result: parsed,
    stock
  }
};

let parsed = $json;

if ($json.output && typeof $json.output === "string") {
  try {
    const cleaned = $json.output.replace(/```json\n?|```/g, "").trim();
    parsed = JSON.parse(cleaned);
  } catch (e) {
    parsed = $json;
  }
} else if ($json.content?.parts?.[0]?.text) {
  try {
    parsed = JSON.parse($json.content.parts[0].text);
  } catch (e) {
    parsed = $json;
  }
}

// If Gemini already returns object at top-level
if (parsed && parsed.gemini_result) parsed = parsed.gemini_result;

const stock =
  parsed?.stock ||
  $json?.stock ||
  $json?.ticker ||
  $json?.symbol ||
  "UNKNOWN";

return {
  json: {
    gemini_result: parsed,
    stock
  }
};
